const d = $json.data;

// Markers that identify YOUR OWN team members in the speaker list.
// IMPORTANT: replace these with words that appear in your team's
// speaker names (for example your company name or a teammate name).
// Any speaker whose name contains one of these is treated as internal.
const internalMarkers = ['your company name', 'your team name'];

// The client is the first speaker who is NOT on your team.
const speakerNames = (d.speakers || []).map(s => s.name).filter(Boolean);
const clientName = speakerNames.find(n =>
  !internalMarkers.some(m => n.toLowerCase().includes(m.toLowerCase()))
) || '';

// Build the full transcript text as "Speaker: line" for each sentence.
const fullTranscript = (d.sentences || [])
  .map(s => `${s.speaker_name}: ${s.text}`).join('\n');

return [{ json: {
  meetingId: d.id,
  clientName,
  fullTranscript,
  date: d.dateString || ''
}}];
